import com.pinterest.ktlint.test.KtLintAssertThat.Companion.assertThatRule
import org.junit.jupiter.api.Test

class MultiLineIfElseReproTest {
    private val multiLineIfElseRuleAssertThat = assertThatRule { MultiLineIfElseRule() }

    @Test
    fun `Issue repro - else if should not be wrapped in braces if it is already valid`() {
        val code =
            """
            val x = if (showFilter) {
                1
            } else if (activeTabIndex.value == 0) {
                2
            } else {
                null
            } ?: 0
            """.trimIndent()
        multiLineIfElseRuleAssertThat(code).hasNoLintViolations()
    }

    @Test
    fun `Issue repro - else if with plus should not be wrapped in braces`() {
        val code =
            """
            val foo = if (bar1) {
                "bar1"
            } else if (bar2) {
                "bar2"
            } else {
                "bar3"
            }.plus("foo")
            """.trimIndent()
        multiLineIfElseRuleAssertThat(code).hasNoLintViolations()
    }
}
"}

